6810   // 14 out of the 20 (10 predicates * 2 constants) possible combinations.
6811   // Cases not handled by InstSimplify are always 'not' of Op0.
6812   if (match(B, m_Zero())) {
6813     switch (I.getPredicate()) {
6814       case CmpInst::ICMP_EQ:  // A ==   0 -> !A
6815       case CmpInst::ICMP_ULE: // A <=u  0 -> !A
6816       case CmpInst::ICMP_SGE: // A >=s  0 -> !A
6817         return BinaryOperator::CreateNot(A);
6818       default:
6819         llvm_unreachable("ICmp i1 X, C not simplified as expected.");
6820     }
6821   } else if (match(B, m_One())) {
6822     switch (I.getPredicate()) {
6823       case CmpInst::ICMP_NE:  // A !=  1 -> !A
6824       case CmpInst::ICMP_ULT: // A <u  1 -> !A
6825       case CmpInst::ICMP_SGT: // A >s -1 -> !A
6826         return BinaryOperator::CreateNot(A);
6827       default:
6828         llvm_unreachable("ICmp i1 X, C not simplified as expected.");
6829     }
6830   }
6831 
6832   switch (I.getPredicate()) {
6833   default:
6834     llvm_unreachable("Invalid icmp instruction!");
6835   case ICmpInst::ICMP_EQ:
6836     // icmp eq i1 A, B -> ~(A ^ B)
